import{C as t,o as i,c as o,a5 as a,E as r}from"./chunks/framework.CW28V7p_.js";const c=JSON.parse('{"title":"6. Token-2022 (newer token standard)","description":"","frontmatter":{},"headers":[],"relativePath":"module-2/6-token-2022.md","filePath":"module-2/6-token-2022.md","lastUpdated":1780937944000}'),l={name:"module-2/6-token-2022.md"},k=Object.assign(l,{setup(d){const n={id:"m2-6-token-2022",title:"🧠 Mini-check: Token-2022",intro:"2 питання.",questions:[{type:"compare",q:"SPL Token (legacy) vs Token-2022?",ideal:`SPL Token (legacy, TokenkegQ...): original Solana token standard. Simple: mint, transfer, burn, freeze. Most existing tokens use це (USDC, JTO, JitoSOL, etc.).

Token-2022 (TokenzQd...): newer standard supporting "extensions" — opt-in features per token. Extensions include:
- Transfer fees (mint takes % per transfer)
- Confidential transfers (encrypted amounts)
- Interest-bearing tokens (auto-accrue)
- Non-transferable (soul-bound NFTs)
- Default account state (freeze by default)
- Permanent delegate (mint authority always can move tokens)
- Transfer hooks (custom program runs per transfer)
- Metadata pointer (link to NFT metadata)

Ключова різниця: Token-2022 extensible, legacy fixed feature set. Compatibility: not interchangeable — mints either у legacy OR в 2022, не both.

Migration: legacy tokens won't auto-upgrade. New tokens choose either. Most major existing tokens stick з legacy для compatibility.`,explanation:"Module 2.6."},{type:"mcq",q:"Token-2022 use cases де extensions matter:",options:["RWA (real-world assets): need permanent delegate для compliance freeze","Stablecoins: confidential transfers для privacy","Loyalty tokens: non-transferable soul-bound","Interest-bearing instruments: auto-accrue без manual claim"],correct:[0,1,2,3],explanation:"Всі real use cases. Module 2.6."}]};return(h,e)=>{const s=t("Quiz");return i(),o("div",null,[e[0]||(e[0]=a(`<h1 id="_6-token-2022-newer-token-standard" tabindex="-1">6. Token-2022 (newer token standard) <a class="header-anchor" href="#_6-token-2022-newer-token-standard" aria-label="Permalink to &quot;6. Token-2022 (newer token standard)&quot;">​</a></h1><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p><strong>Token-2022</strong> = newer Solana token standard. Same basics як legacy SPL Token + &quot;extensions&quot; — opt-in features per mint. Important: not interchangeable з legacy tokens. New use cases enabled (transfer fees, confidential transfers, RWAs, soul-bound NFTs).</p><h2 id="two-token-programs-co-exist" tabindex="-1">Two token programs co-exist <a class="header-anchor" href="#two-token-programs-co-exist" aria-label="Permalink to &quot;Two token programs co-exist&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SPL Token (legacy):      TokenkegQfeZyiNwAJbNbGKPFXCWuBvf9Ss623VQ5DA</span></span>
<span class="line"><span>Token-2022 (newer):      TokenzQdBNbLqP5VEhdkAS6EPFLC1PHnBqCXEpPxuEb</span></span></code></pre></div><p>Both run on mainnet. Tokens belong до one or other (mint&#39;s <code>owner</code> field). USDC, JTO, JitoSOL = legacy. Many newer tokens (especially RWAs, niche use cases) = Token-2022.</p><h2 id="extension-types" tabindex="-1">Extension types <a class="header-anchor" href="#extension-types" aria-label="Permalink to &quot;Extension types&quot;">​</a></h2><p>Mint можуть enable any subset extensions at creation time:</p><h3 id="transfer-fees" tabindex="-1">Transfer fees <a class="header-anchor" href="#transfer-fees" aria-label="Permalink to &quot;Transfer fees&quot;">​</a></h3><p>Per-transfer % goes до specific authority. Use cases:</p><ul><li>Royalty payments (NFT-style)</li><li>Protocol revenue</li><li>Anti-spam mechanism</li></ul><h3 id="confidential-transfers" tabindex="-1">Confidential transfers <a class="header-anchor" href="#confidential-transfers" aria-label="Permalink to &quot;Confidential transfers&quot;">​</a></h3><p>Use zero-knowledge proofs for hiding amounts. Privacy-preserving. Compliance considerations (requires special auditor key).</p><h3 id="interest-bearing" tabindex="-1">Interest-bearing <a class="header-anchor" href="#interest-bearing" aria-label="Permalink to &quot;Interest-bearing&quot;">​</a></h3><p>Token balance auto-grows based on configured interest rate. No manual claim. Use:</p><ul><li>Yield-bearing stablecoins</li><li>Bond representations</li></ul><h3 id="non-transferable-soul-bound" tabindex="-1">Non-transferable (soul-bound) <a class="header-anchor" href="#non-transferable-soul-bound" aria-label="Permalink to &quot;Non-transferable (soul-bound)&quot;">​</a></h3><p>Once received, cannot transfer. Use:</p><ul><li>Achievements / badges</li><li>Identity verification</li><li>Membership tokens</li></ul><h3 id="default-frozen-state" tabindex="-1">Default frozen state <a class="header-anchor" href="#default-frozen-state" aria-label="Permalink to &quot;Default frozen state&quot;">​</a></h3><p>New token accounts frozen until explicit unfreeze. Use:</p><ul><li>Whitelisted token (only approved holders)</li><li>KYC-gated tokens</li></ul><h3 id="permanent-delegate" tabindex="-1">Permanent delegate <a class="header-anchor" href="#permanent-delegate" aria-label="Permalink to &quot;Permanent delegate&quot;">​</a></h3><p>Mint authority always can move/burn tokens. Use:</p><ul><li>Compliance freezing (regulator requires)</li><li>Stablecoin issuer redemption mechanism</li></ul><h3 id="transfer-hooks" tabindex="-1">Transfer hooks <a class="header-anchor" href="#transfer-hooks" aria-label="Permalink to &quot;Transfer hooks&quot;">​</a></h3><p>Custom program runs on each transfer. Validates або triggers side effects:</p><ul><li>Compliance checks per transfer</li><li>Triggering external programs</li><li>Logging</li></ul><h3 id="metadata-pointer" tabindex="-1">Metadata pointer <a class="header-anchor" href="#metadata-pointer" aria-label="Permalink to &quot;Metadata pointer&quot;">​</a></h3><p>Embeds metadata reference directly у mint. Replaces external metadata accounts (Metaplex pattern). Simpler NFT setup.</p><h2 id="use-case-examples" tabindex="-1">Use case examples <a class="header-anchor" href="#use-case-examples" aria-label="Permalink to &quot;Use case examples&quot;">​</a></h2><h3 id="rwa-real-world-assets-tokens" tabindex="-1">RWA (Real World Assets) tokens <a class="header-anchor" href="#rwa-real-world-assets-tokens" aria-label="Permalink to &quot;RWA (Real World Assets) tokens&quot;">​</a></h3><p>E.g., tokenized treasury bills. Need:</p><ul><li>Permanent delegate (regulator can freeze/burn)</li><li>Transfer hooks (KYC/sanctions checks)</li><li>Interest-bearing (yield accrual)</li></ul><p>→ Token-2022 з всіма цими extensions.</p><h3 id="privacy-stablecoin" tabindex="-1">Privacy stablecoin <a class="header-anchor" href="#privacy-stablecoin" aria-label="Permalink to &quot;Privacy stablecoin&quot;">​</a></h3><p>E.g., regulated privacy token. Need:</p><ul><li>Confidential transfers</li><li>Permanent delegate (for compliance)</li></ul><p>→ Token-2022 з confidential transfers + permanent delegate.</p><h3 id="membership-token" tabindex="-1">Membership token <a class="header-anchor" href="#membership-token" aria-label="Permalink to &quot;Membership token&quot;">​</a></h3><p>E.g., DAO governance non-transferable token. Need:</p><ul><li>Non-transferable (soul-bound)</li></ul><p>→ Token-2022 з non-transferable extension.</p><h3 id="standard-fungible-usdc-style" tabindex="-1">Standard fungible (USDC-style) <a class="header-anchor" href="#standard-fungible-usdc-style" aria-label="Permalink to &quot;Standard fungible (USDC-style)&quot;">​</a></h3><p>Just basic transfer + freeze. No extensions needed.</p><p>→ Either Token-2022 (без extensions) OR legacy SPL Token (likely choice для standard tokens).</p><h2 id="cli-usage" tabindex="-1">CLI usage <a class="header-anchor" href="#cli-usage" aria-label="Permalink to &quot;CLI usage&quot;">​</a></h2><p><code>spl-token</code> CLI supports both. Specify program:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Legacy (default)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">spl-token</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create-token</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Token-2022</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">spl-token</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create-token</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --program-id</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> TokenzQdBNbLqP5VEhdkAS6EPFLC1PHnBqCXEpPxuEb</span></span></code></pre></div><p>For accounts:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Show all token balances (auto-detects both programs)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">spl-token</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> accounts</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Create ATA для Token-2022 mint</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">spl-token</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create-account</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">TOKEN_2022_MIN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">T</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --program-id</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> TokenzQdBNbLqP5VEhdkAS6EPFLC1PHnBqCXEpPxuEb</span></span></code></pre></div><h2 id="verify-which-program-owns-mint" tabindex="-1">Verify which program owns mint <a class="header-anchor" href="#verify-which-program-owns-mint" aria-label="Permalink to &quot;Verify which program owns mint&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> account</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">MINT_ADDRES</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">S</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Owner</span></span></code></pre></div><ul><li><code>Owner: TokenkegQfeZyiNwAJbNbGKPFXCWuBvf9Ss623VQ5DA</code> → legacy SPL Token</li><li><code>Owner: TokenzQdBNbLqP5VEhdkAS6EPFLC1PHnBqCXEpPxuEb</code> → Token-2022</li></ul><h2 id="connect-to-your-work" tabindex="-1">Connect to your work <a class="header-anchor" href="#connect-to-your-work" aria-label="Permalink to &quot;Connect to your work&quot;">​</a></h2><p>Як validator operator, ти не creates tokens — but може receive them (rewards, treasury holdings):</p><ul><li><strong>Jito tips</strong>: native SOL (no token program needed)</li><li><strong>DZ rewards</strong>: likely Token-2022 (modern protocol)</li><li><strong>JitoSOL holdings</strong>: legacy SPL Token</li><li><strong>USDC у treasury</strong>: legacy SPL Token</li></ul><p>When configuring <code>--rewards-token-owner</code> (DZ context з 2026-06-08), the token program matters:</p><ul><li>Owner wallet still standard SOL wallet (System Program)</li><li>ATA derivation differs slightly between programs (different program in seeds)</li><li>DZ tooling handles this internally</li></ul><h2 id="migration-considerations" tabindex="-1">Migration considerations <a class="header-anchor" href="#migration-considerations" aria-label="Permalink to &quot;Migration considerations&quot;">​</a></h2><p>Legacy → Token-2022 migration NOT auto. Users must:</p><ol><li>Burn legacy tokens</li><li>Receive new Token-2022 tokens through bridge contract</li><li>Update wallet handling</li></ol><p>Major existing tokens (USDC, JTO, etc.) unlikely migrate due to ecosystem inertia (DEXes, dApps integrated з legacy).</p><p>New token launches increasingly choose Token-2022 for flexibility.</p><h2 id="mini-quiz" tabindex="-1">Mini-quiz <a class="header-anchor" href="#mini-quiz" aria-label="Permalink to &quot;Mini-quiz&quot;">​</a></h2>`,65)),r(s,{data:n}),e[1]||(e[1]=a('<h2 id="glossary-additions" tabindex="-1">Glossary additions <a class="header-anchor" href="#glossary-additions" aria-label="Permalink to &quot;Glossary additions&quot;">​</a></h2><p><a href="/glossary#t"><code>Token-2022</code></a>, <a href="/glossary#t"><code>Token extensions</code></a>, <a href="/glossary#t"><code>Transfer fees</code></a>, <a href="/glossary#c"><code>Confidential transfers</code></a>, <a href="/glossary#n"><code>Non-transferable</code></a>, <a href="/glossary#t"><code>Transfer hooks</code></a></p><h2 id="external-refs" tabindex="-1">External refs <a class="header-anchor" href="#external-refs" aria-label="Permalink to &quot;External refs&quot;">​</a></h2><ul><li><a href="https://spl.solana.com/token-2022" target="_blank" rel="noreferrer">Token-2022 documentation</a></li><li><a href="https://spl.solana.com/token-2022/extensions" target="_blank" rel="noreferrer">Token-2022 extensions guide</a></li></ul><hr><p><strong>Попередньо:</strong> <a href="/module-2/5-pda-deep">← 5. PDA deep</a></p>',6))])}}});export{c as __pageData,k as default};
